#!/usr/bin/env bash
# agentic.sh — Agentic Protocol CLI for 加密链上交易.
# Auto-generated by cli_writer.py. Source: synthesis.md Section 9.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
# shellcheck source=../lib/common.sh
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="加密链上交易"
DIM_COUNT=7

usage() {
  cat <<EOF
agentic.sh — Agentic Protocol CLI for ${INDUSTRY}

拿到 ${INDUSTRY} 行业的新问题时，按 ${DIM_COUNT} 个研究维度做功课再答。
不直接给答案，而是引导你用资深从业者的研究维度收集信息。

USAGE:
  ./agentic.sh                # interactive walkthrough
  ./agentic.sh --dry-run      # walk through but skip file write
  ./agentic.sh --json         # emit JSON to stdout
  ./agentic.sh --explain      # show backing mental models + sources
  ./agentic.sh --help         # this message
EOF
}

explain() {
  cat <<'EOT'
这个 Agentic Protocol 把这一行人面对新问题的研究维度结构化。

研究维度 (7 个):
  9.1 流动性 / 宏观环境定位
  9.2 标的链上尽调
  9.3 资金流与聪明钱
  9.4 叙事 / 板块轮动定位
  9.5 衍生品 / 市场结构
  9.6 信息源利益冲突核查
  9.7 风控与仓位前置

背后的心智模型:
  • 流动性是母潮，价格是浪（先读流动性，再读叙事）: 加密资产长期是「全球美元流动性的温度计」——价格的大方向由央行/财政释放的流动性母潮决定，单个币的叙事只是骑在母潮上的浪；资深人先判断「现在流动性在扩张还是收缩」，再谈选币。
  • 先定能亏多少，再谈能赚多少（仓位/风控 > 入场与预测）: 交易的 edge 不在「预测对方向」，而在「每笔先定义 1R 风险（在哪证明自己错）+ 用 R 倍数记录复盘」——把每笔交易当一次概率抽样，活下来的人靠期望值而非单次暴击赚钱。
  • 叙事即基本面（反身性：价格→采用→价格的自我强化环）: 在加密里叙事不是基本面的附属，叙事本身就是可交易的基本面——Soros 反身性在这一行被放大到极致：价格上涨吸引注意力与资金、又推高价格，繁荣与崩溃由同一个自我强化环驱动。

来源: synthesis.md Section 9 + Section 1.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a DIM_TITLES=(
  "流动性 / 宏观环境定位"
  "标的链上尽调"
  "资金流与聪明钱"
  "叙事 / 板块轮动定位"
  "衍生品 / 市场结构"
  "信息源利益冲突核查"
  "风控与仓位前置"
)
declare -a DIM_QUESTIONS=(
  "全球美元流动性方向、美联储/RRP/财政、稳定币总市值变化、BTC 市占率（BTC.D）走向。"
  "代币经济学 / 解锁 vesting 日历 / 持仓分布与集中度 / LP 锁仓 / honeypot 与合约权限（mint/blacklist/proxy）。"
  "交易所净流入/流出、巨鲸地址动向、聪明钱标签与早期买家、是否存在反向狩猎结构。"
  "当前主导叙事、attention 流向、板块强弱与轮动、该叙事是否已成公共知识（晚期）。"
  "资金费率、未平仓 OI、清算热图、多空比、杠杆拥挤度。"
  "信号发布者的持仓 / 基金 / 返佣 / 项目关系 / 历史准确率，是否 talk-his-book。"
  "单笔 1R 风险、与现有持仓的相关性、最大回撤承受、自托管安全状态（授权/钱包分层）。"
)
declare -a DIM_SOURCES=(
  "Arthur Hayes 博客 / Lyn Alden（宏观框架）、CryptoQuant & Glassnode（链上流动性指标）、DefiLlama 稳定币页。"
  "Token Unlocks（解锁）、Arkham/Nansen（持仓）、GoPlus/RugCheck/De.Fi（合约扫描）、Etherscan/Solscan。"
  "Nansen（smart money 标签）、Arkham（实体标注）、CryptoQuant（交易所流向）。"
  "Twitter/X（Crypto Twitter）、Messari Theses（年度叙事）、Dexscreener trending。"
  "Coinglass（费率/清算/OI）、各交易所衍生品数据。"
  "发布者公开披露、其链上地址（Arkham）、ZachXBT 等反诈取证。"
  "自己的交易日志、Revoke.cash（授权）、钱包分层方案。"
)
declare -a DIM_OUTPUT_FORMATS=(
  "一句话定位「当前处于流动性扩张/收缩象限」+ 据此给出总风险敞口建议（加/中性/降）。"
  "红旗清单（解锁砸盘风险/庄持仓/可增发/貔貅）+ 结论「可投 / 观望 / 避开」+ 关键不确定项。"
  "「资金在进还是出」+ 信号可信度（标签需多源交叉）+ 被反向狩猎的风险提示。"
  "「当前 meta 是什么 + 处于启动/加速/过剩哪段 + 我是否在接最后一棒」+ 下一轮候选叙事。"
  "「杠杆拥挤度 + 大概率挤压方向（多杀多/空杀空）+ 清算价地图」，标明数据时点（随市场快速变）。"
  "「该信号的立场偏向（看多/看空谁受益）+ 去偏后的可信度权重」，杀猪盘特征命中即拉黑。"
  "「仓位大小 + 止损/失效位 + 钱包隔离方案（热/冷/可归零额）」，没有失效定义则结论为「不开仓」。"
)
declare -a DIM_FINDINGS=()

if [[ $JSON -eq 0 ]]; then
  ms_section "${INDUSTRY} · Agentic Protocol"
  ms_info "拿到的问题是什么? (输入完后，敲一个空行结束)"
  echo
fi

PROBLEM="$(ms_read_multiline)"
ms_buffer_append "# ${INDUSTRY} — Agentic Protocol Report"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## 问题"
ms_buffer_append ""
ms_buffer_append "$PROBLEM"
ms_buffer_append ""

for i in "${!DIM_TITLES[@]}"; do
  if [[ $JSON -eq 0 ]]; then
    ms_section "${DIM_TITLES[$i]}"
    echo "看什么:    ${DIM_QUESTIONS[$i]}"
    echo "在哪看:    ${DIM_SOURCES[$i]}"
    echo "输出格式:  ${DIM_OUTPUT_FORMATS[$i]}"
    echo
    ms_prompt "你的发现 / 推断 (空行结束):"
    echo
  fi
  finding="$(ms_read_multiline)"
  DIM_FINDINGS+=("$finding")

  ms_buffer_append "## ${DIM_TITLES[$i]}"
  ms_buffer_append ""
  ms_buffer_append "**看什么**: ${DIM_QUESTIONS[$i]}"
  ms_buffer_append ""
  ms_buffer_append "**在哪看**: ${DIM_SOURCES[$i]}"
  ms_buffer_append ""
  ms_buffer_append "**发现**:"
  ms_buffer_append ""
  ms_buffer_append "$finding"
  ms_buffer_append ""
done

if [[ $JSON -eq 1 ]]; then
  args=("problem" "$PROBLEM")
  for i in "${!DIM_TITLES[@]}"; do
    args+=("dim_${i}_title" "${DIM_TITLES[$i]}")
    args+=("dim_${i}_finding" "${DIM_FINDINGS[$i]}")
  done
  ms_emit_json "${args[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "agentic-protocol"
fi
